import React, { useEffect, useState } from 'react';
import CardProduto from '../CardProduto';
import Column from '../Column';
import * as C from './style';

function Main({ pedidos, pageRender, produtos }) {

    const [ pedidos1, setPedidos1 ] = useState([]);    
    const [ pedidos2, setPedidos2 ] = useState([]);    
    const [ pedidos3, setPedidos3 ] = useState([]);    
    const [ pedidos4, setPedidos4 ] = useState([]);    
    const [ pedidos5, setPedidos5 ] = useState([]);    
    
    if(pedidos.length > 0){
        let pedidosFiltrados1 = pedidos.filter( e => e.horaEntrega === "19:30")
        let pedidosFiltrados2 = pedidos.filter( e => e.horaEntrega === "20:00")
        let pedidosFiltrados3 = pedidos.filter( e => e.horaEntrega === "20:30")
        let pedidosFiltrados4 = pedidos.filter( e => e.horaEntrega === "21:00")
        let pedidosFiltrados5 = pedidos.filter( e => e.horaEntrega === "21:30")
        setPedidos1(pedidosFiltrados1)
        setPedidos2(pedidosFiltrados2)
        setPedidos3(pedidosFiltrados3)
        setPedidos4(pedidosFiltrados4)
        setPedidos5(pedidosFiltrados5)
    }

    
    if(pageRender === "Pedidos" && pedidos.length > 0){
        return (
            <C.ContainerPedidos>
                <Column title='19:30' pedidos={pedidos1}/>
            </C.ContainerPedidos>
        )
    }

/*     if(pageRender === "Produtos"){
        console.log(produtos);
        return (
            <C.ContainerProdutos>
                {produtos.map( produto => (
                    <CardProduto key={produto.id} produto={produto}/>
                ))}
            </C.ContainerProdutos>
        )
    } */

    if(pageRender === "Pagamentos"){
        return (<div>Pagamentos</div>)
    }

    if(pageRender === "Controle Interno"){
        return (<div>Controle Interno</div>)
    }
    
}

export default Main
